`handleRotate` collects the new secret value via `window.prompt(...)`, which is plain-text (not password-masked) and easy to leak via screen recording/shoulder surfing. For secret entry, prefer a controlled modal/form field using `<input type="password">` (and avoid putting the secret into a JS `prompt` string).
```suggestion
    if (!window.confirm(`Are you sure you want to trigger a rotation for ${secSlug}?`)) {
      return;
    }

    // Create a simple modal overlay with a password input for the new secret value
    const overlay = document.createElement('div');
    overlay.style.position = 'fixed';
    overlay.style.inset = '0';
    overlay.style.backgroundColor = 'rgba(0, 0, 0, 0.5)';
    overlay.style.display = 'flex';
    overlay.style.alignItems = 'center';
    overlay.style.justifyContent = 'center';
    overlay.style.zIndex = '9999';

    const modal = document.createElement('div');
    modal.style.backgroundColor = '#ffffff';
    modal.style.padding = '1.5rem';
    modal.style.borderRadius = '0.5rem';
    modal.style.minWidth = '300px';
    modal.style.maxWidth = '90%';
    modal.style.boxShadow = '0 10px 25px rgba(0, 0, 0, 0.2)';

    const title = document.createElement('h2');
    title.textContent = `Rotate secret: ${secSlug}`;
    title.style.marginTop = '0';

    const form = document.createElement('form');

    const label = document.createElement('label');
    label.textContent = 'Enter NEW secure value:';
    label.style.display = 'block';
    label.style.marginBottom = '0.5rem';

    const input = document.createElement('input');
    input.type = 'password';
    input.style.width = '100%';
    input.style.boxSizing = 'border-box';
    input.style.marginBottom = '1rem';

    const buttonsWrapper = document.createElement('div');
    buttonsWrapper.style.display = 'flex';
    buttonsWrapper.style.justifyContent = 'flex-end';
    buttonsWrapper.style.gap = '0.5rem';

    const cancelBtn = document.createElement('button');
    cancelBtn.type = 'button';
    cancelBtn.textContent = 'Cancel';

    const submitBtn = document.createElement('button');
    submitBtn.type = 'submit';
    submitBtn.textContent = 'Rotate';

    const cleanup = () => {
      if (overlay.parentNode) {
        overlay.parentNode.removeChild(overlay);
      }
    };

    cancelBtn.onclick = (e) => {
      e.preventDefault();
      cleanup();
    };

    form.onsubmit = (e) => {
      e.preventDefault();
      const val = input.value;
      if (!val) {
        // Basic feedback; keep it minimal to avoid leaking the secret
        alert('Please provide a new secure value to rotate the secret.');
        return;
      }
      rotateOp.mutate({ slug: secSlug, plaintext: val });
      cleanup();
    };

   .buttonsWrapper.appendChild(cancelBtn);
    buttonsWrapper.appendChild(submitBtn);

    form.appendChild(label);
    form.appendChild(input);
    form.appendChild(buttonsWrapper);

    modal.appendChild(title);
    modal.appendChild(form);
    overlay.appendChild(modal);
    document.body.appendChild(overlay);

    // Focus the input for better UX
    input.focus();
```
